CREATE VIEW `vw_expense_balance` AS select "category_id", "category_name", CAST(SUM(value) AS INTEGER) as "total" from "vw_expense_with_category" where date(date, 'unixepoch', '-3 hours') >= date('now', '-3 hours', 'start of month') AND date(date, 'unixepoch', '-3 hours') < date('now', '-3 hours' , '+1 month', 'start of month') group by "vw_expense_with_category"."category_id" order by "vw_expense_with_category"."category_id";--> statement-breakpoint
CREATE VIEW `vw_expense_limit_balance` AS select "vw_expense_limit_with_category"."id", "vw_expense_limit_with_category"."name", "vw_expense_limit_with_category"."value", "vw_expense_limit_with_category"."period_id", "vw_expense_limit_with_category"."start_date", "vw_expense_limit_with_category"."end_date", "vw_expense_limit_with_category"."category_id" as "category_id", "vw_expense_limit_with_category"."category_name" as "category_name", "vw_expense_limit_with_category"."period_name" as "period_name", "total" from "vw_expense_limit_with_category" left join "vw_expense_balance" on "vw_expense_limit_with_category"."category_id" = "vw_expense_balance"."category_id";